INSERT INTO `wp_posts` VALUES (2,1052,'2011-11-24 19:40:09','2011-11-24 19:40:09','<table border=\"0\" cellspacing=\"0\" cellpadding=\"2\" bgcolor=\"#ffffff\">\n<tbody>\n<tr>\n<td><a style=\"clear: left; float: left; margin-bottom: 1em; margin-right: 1em;\" href=\"http://lh3.ggpht.com/_8I7HnI7Y_qA/StZ8KDZEDAI/AAAAAAAABvE/lk5lym0UoIg/s1600/logo_hopham3.jpg\"><img src=\"http://lh3.ggpht.com/_8I7HnI7Y_qA/StZ8KDZEDAI/AAAAAAAABvE/lk5lym0UoIg/s200/logo_hopham3.jpg\" alt=\"\" border=\"0\" /></a>Chúng tôi xin chân thành cảm ơn các ý kiến đóng góp, các bài viết gửi về của bạn đọc gần xa trong suốt thời gian qua. Nếu bạn có góp ý hay viết bài tham gia bản tin nội tộc, vui lòng liên hệ theo địa chỉ dưới đây:\n\n* TS.<strong> Phạm Vũ Câu</strong>\n\nTầng 2, Số 23 Nguyễn Đình Chiều, Q. Hai Bà Trưng, Hà Nội.\n\nĐT: 0913 241 718\n\nEmail: contact@localhost.test\n\n* <strong>Email Ban Biên Tập Trang Web</strong>:\n\n<span style=\"color: blue;\">editor@localhost.test</span></td>\n</tr>\n</tbody>\n</table>\n* Nếu bạn cần hỗ trợ kỹ thuật hoặc liên hệ đặt logo/link liên kết website,...\n\nVui lòng gửi mail đến Admin:\n\n<strong>Phạm Quang Khoát</strong>;\n\nEmail: admin@localhost.test\n\n<hr />','Liên hệ','','trash','open','closed','','sample-page__trashed','','','2021-12-28 23:41:18','2021-12-28 16:41:18','',0,'http://demo.hophamvietnam.org/?page_id=2',3,'page','',0),(148,1052,'2012-01-10 03:18:53','2012-01-10 03:18:53','<address>[<a href=\"http://www.hophamvietnam.org/?cat=77\">Bấm vào đây để xem tin bài trong chuyên mục</a>]</address>.\r\n\r\n.\r\n<h1 style=\"text-align: center;\"><span style=\"color: #800000;\"> LỜI BAN BIÊN TẬP  </span></h1>\r\n<h1 style=\"text-align: center;\"><span style=\"color: #800000;\">Trang Web hophamvietnam.org </span></h1>\r\n<p style=\"text-align: center;\"><em><a href=\"http://www.hophamvietnam.org/wp-content/uploads/2012/12/TP1.jpg\"><img class=\"aligncenter size-thumbnail wp-image-3903\" title=\"TP\" src=\"http://www.hophamvietnam.org/wp-content/uploads/2012/12/TP1-150x150.jpg\" alt=\"\" width=\"150\" height=\"150\" /></a></em></p>\r\n<em>               </em><span style=\"color: #000080;\"><strong><em>“Chim có tổ, người có tông, đời phát triển không quên nền tông tộc;</em></strong></span>\r\n\r\n<span style=\"color: #000080;\"><strong><em>                 Nước có nguồn, cây có cội, sống văn minh càng nhớ gốc giống nòi”</em></strong></span>\r\n<p style=\"text-align: justify;\"><em>          Nhớ lời dạy của tiên tổ, họ Phạm chúng ta đã nhà nhà, chi họ đều lo ghi chép gia phả để lưu truyền cho hậu thế biết và ghi nhớ cội nguồn, thế thứ trong tình đồng tộc mà quan tâm lẫn nhau, giữ gìn và phát huy truyên thống dòng họ.</em></p>\r\n<p style=\"text-align: justify;\"><em>            Trải qua lịch sử hàng nghìn năm từ khi người Việt ta có tên và họ, điều kiện  thời thế đổi thay; gia đình, dòng họ phân tán lan tỏa muôn nơi sinh cơ lập nghiệp nên gia phả cũng không được lập ngay từ đầu hoặc không được hệ thống và cập nhật liên tục. Vậy nên việc xác định cây phả hệ của cả dòng họ là điều không thể, ngay cả việc xác định mối liên hệ của các dòng, chi họ Phạm ta trong một địa phương cũng gặp nhiều khó khăn.</em></p>\r\n<p style=\"text-align: justify;\"><em>              Hoạt động “Tìm về cội nguồn, kết nối dòng họ” muốn có kết quả phải dựa vào gia phả của từng dòng, từng chi họ. Lâu nay Hội đồng họ Phạm từ trung ương đến địa phương đã quan tâm và muốn đẩy mạnh hoạt động này nhưng lực bất tòng tâm nên kết quả còn hạn chế. Để khâu “Tìm về cội nguồn, kết nối dòng họ” được đẩy mạnh và có kết quả, từ nay Trang Web hophamvietnam.org mở lại chuyên mục </em><em>Tộc phả - Tộc ước, </em><em>sẽ đăng tải Danh mục các dòng/ chi họ Phạm đã có và chuyển cho Hội đồng toàn quốc Họ Phạm Việt Nam và lần lượt đăng tải </em><em>Tổng quan</em><em> từng dòng họ Phạm để bà con các dòng/ chi họ nghiên cứu, đối chiếu, tìm mối liên quan với dòng họ mình và có kế hoạch kết nối.</em></p>\r\n<p style=\"text-align: justify;\"><em>Ban biên tập rất mong Hội đồng các dòng/ chi họ trong cả nước nhiệt tình hưởng ứng, tiếp tục chia sẻ thông tin tư liệu tộc phả- tộc ước của dòng/ chi họ mình. Thông tin tộc phả có thể là toàn bộ gia phả hoặc bài giới thiệu Tổng quandòng/ chi họ  với các thông tin cơ bản như bài Tổng quan Dòng họ Phạm Văn Viết ở chuyên mục này.</em></p>\r\n<p style=\"text-align: justify;\"><em>Thông tin tư liệu xin gửi về user@localhost.test hoặc <a href=\"mailto:editor@localhost.test\">editor@localhost.test</a> </em></p>\r\n<p style=\"text-align: center;\" align=\"center\"><strong>Tổng Biên tập</strong></p>\r\n<p align=\"center\"><strong>TS. Phạm Vũ Câu</strong></p>\r\n.\r\n\r\n<address>[<a href=\"http://www.hophamvietnam.org/?cat=77\">Bấm vào đây để xem tin bài trong chuyên mục</a>]</address>','Tộc phả - Tộc ước','','trash','open','open','','danh-cho-ng%c6%b0%e1%bb%9di-m%e1%bb%9bi__trashed','','','2021-12-28 23:41:21','2021-12-28 16:41:21','',0,'http://www.hophamvietnam.org/?page_id=148',0,'page','',1),(29634,1052,'2026-03-02 14:06:40','2026-03-02 07:06:40','','z7574875285985_a04477805064a1131d4f4e7fb32d42f8','','inherit','open','closed','','z7574875285985_a04477805064a1131d4f4e7fb32d42f8','','','2026-03-02 14:06:40','2026-03-02 07:06:40','',29628,'http://localhost:8080/wp-content/uploads/2026/03/z7574875285985_a04477805064a1131d4f4e7fb32d42f8.jpg',0,'attachment','image/jpeg',0),(29680,1052,'2026-03-06 22:26:12','2026-03-06 15:26:12','','18','','inherit','open','closed','','18','','','2026-03-06 22:26:12','2026-03-06 15:26:12','',29662,'http://localhost:8080/wp-content/uploads/2026/03/18.jpg',0,'attachment','image/jpeg',0),(29662,1052,'2026-03-06 22:26:55','2026-03-06 15:26:55','TIN HỘI NGHỊ TỔNG KẾT 2025 VÀ KỶ NIỆM NGÀY QUỐC TẾ PHỤ NỮ 8/3\r\nCỦA CLB CON GÁI CON DÂU HỌ PHẠM HẢI PHÒNG.\r\n\r\nSáng nay, ngày 06/03/2026 tại Cung Eden Hai Đang Plazza (số 24 - Trần Khánh Dư - Hải Phòng). CLB CGCD HP Hải Phòng đã tổ chức Hội nghị Tổng Kết hoạt động năm 2025 và Kỷ niệm 116 năm (1910 - 2026) ngày Quốc Tế Phụ Nữ 8/3.\r\nHội nghị được đón tiếp các vị khách quý, các vị đại biểu: Ông TS. Phạm Tiến Dũng PCT HĐHPVN - CT HĐHP TPHP; Ông Phạm Tiến Du UVTT HĐHP VN - PCT HĐHP TP Phụ trách phía Đông HP; Ông Phạm Văn Mạnh UVHĐHPVN - PCT Kiêm Tổng Thư Ký HĐHP TP; Ông Phạm Quang Thuấn UVHĐHPVN - PCT HĐHP TP; Ông Phạm Huy Má PCT HĐHP TP; các Ông/Bà đại diện cho HĐHP các Phường/Xã trực thuộc hội đồng họ Phạm TP; các Ông/Bà đại diện HĐGT thôn Bảo Ngãi xã Nguyễn Bỉnh Khiêm HP; các Ông Cố vấn CLBCGCD HP TP cùng 42 Đại biểu trong BCN và các Thành viên CLB CGCD HP TP đã về dự.\r\nMở đầu là chương trình văn nghệ đặc sắc, chất lượng của các diễn viên không chuyên trong CBL và các CLB thành viên Xã/Phường.\r\nSau diễn văn khai mạc Hội nghị và vai trò người phụ nữ Việt Nam nhân kỷ niệm 116 năm ngày quốc tế phụ nữ 8/3 do Bà Phạm Thị Thúy PCN TT CLB trình bày - là trình chiếu video clíp về một số hoạt động của CLB CGCD HP TPHP trong năm 2025, đặc biệt là các hoạt động sau 01/7/2025 đến nay. CLB CGCD HP TPHP đã hoạt động có nề nếp, đoàn kết nhất trí cao xây dựng CLB hoạt động không ngừng vươn lên và đạt được rất nhiều kết quả tốt trong xây dựng CLB . Trong tri ân thiện nguyện và kết nối giữa các HĐHP Xã/Phường, các HĐGT và phong trào văn hóa văn nghệ. (Clip do Cố vấn CLB - Phạm Diệp dựng hình và đọc lời bình).\r\nHội nghị nghe Bà BS. Phạm Tuyết Mai CN CLB trình bày phương hướng hoạt động của CLB CGCD HP TP trong năm 2026. Sau đó là tham luận của các CLB CGCDHP Phường Lê Chân và Xã Hoa Động.\r\nPhát biểu tại Hội nghị; Ông TS Phạm Tiến Dũng CT HĐHP TPHP T/M HĐHP TPHP đã biểu dương những kết quả mà CLB CGCD HP TP đứng đầu là BCN đã hoạt động tích cực và đạt được những kết quả đáng khích lệ. TS Phạm Tiến Dũng đã nêu lên một số công việc có tính định hướng hoạt động của CLB CGCD HP TP trong những năm tới; kỳ vọng CLB là nòng cột trong nhiệm vụ trọng tâm của quý II/2026 đó là Tham gia các hoạt động tại Hội nghị Gặp mặt H ĐHP 6 thành phố tại Huế nhân dịp kỷ niệm 51 năm Giải phóng thành phố Huế (26/3/2026) và chuẩn bị tốt nhất cho Đại hội HĐHP TP lần thứ nhất dự kiến vào cuối quý II/26.\r\nBà BS Phạm Tuyết Mai phát biểu cảm ơn Chủ tịch và xin hứa cùng BCN thực hiện tốt những định hướng mà chủ tịch HĐHP TP đã đặt ra, năm 2026 phấn đấu Đại hội được 3 CLB CGCDHP xã phường và mỗi CLB xã phường hiện có sẽ kết nối kết nạp được thêm 5-10 Thành viên.\r\nHôị nghị kết thúc trong bầu không khí vui vẻ đoàn kết. Các Đại biểu cùng chụp ảnh kỷ niệm.\r\nDưới đây là một số hình ảnh Hội nghị do CVP HĐHP HP - Phạm Diệp ghi hình và đưa tin.\r\nBan TTTL HĐHP HP 06/3/2026.\r\nLưu trữ : <a href=\"https://drive.google.com/drive/folders/1utgHiS_4Gl8rYFmWL0z6rIRXi4pVQQlh?usp=sharing\">https://drive.google.com/drive/folders/1utgHiS_4Gl8rYFmWL0z6rIRXi4pVQQlh?usp=sharing</a>\r\n\r\n<img class=\"alignnone size-full wp-image-29663\" src=\"https://media.hophamvietnam.org/2026/03/1.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29664\" src=\"https://media.hophamvietnam.org/2026/03/2.jpg\" alt=\"\" width=\"1311\" height=\"736\" /> <img class=\"alignnone size-medium wp-image-29665\" src=\"https://media.hophamvietnam.org/2026/03/3.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29666\" src=\"https://media.hophamvietnam.org/2026/03/4.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29667\" src=\"https://media.hophamvietnam.org/2026/03/5.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29668\" src=\"https://media.hophamvietnam.org/2026/03/6.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29669\" src=\"https://media.hophamvietnam.org/2026/03/7.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29670\" src=\"https://media.hophamvietnam.org/2026/03/8.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29671\" src=\"https://media.hophamvietnam.org/2026/03/9.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29672\" src=\"https://media.hophamvietnam.org/2026/03/10.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29673\" src=\"https://media.hophamvietnam.org/2026/03/11.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29674\" src=\"https://media.hophamvietnam.org/2026/03/12.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29675\" src=\"https://media.hophamvietnam.org/2026/03/13.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29676\" src=\"https://media.hophamvietnam.org/2026/03/14.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29677\" src=\"https://media.hophamvietnam.org/2026/03/15.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29678\" src=\"https://media.hophamvietnam.org/2026/03/16.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29679\" src=\"https://media.hophamvietnam.org/2026/03/17.jpg\" alt=\"\" width=\"1311\" height=\"874\" /> <img class=\"alignnone size-medium wp-image-29680\" src=\"https://media.hophamvietnam.org/2026/03/18.jpg\" alt=\"\" width=\"1311\" height=\"874\" />\r\n\r\n&nbsp;','HỘI NGHỊ TỔNG KẾT 2025 VÀ KỶ NIỆM NGÀY QUỐC TẾ PHỤ NỮ 8/3 CỦA CLB CON GÁI CON DÂU HỌ PHẠM HẢI PHÒNG','','publish','open','closed','','hoi-nghi-tong-ket-2025-va-ky-niem-ngay-quoc-te-phu-nu-8-3-cua-clb-con-gai-con-dau-ho-pham-hai-phong','','','2026-03-06 22:27:39','2026-03-06 15:27:39','',0,'http://localhost:8080/?p=29662',0,'post','',0),(10724,1052,'2022-10-27 15:53:28','2014-12-16 03:12:24','Về Họ Phạm Việt Nam Về Hội Đồng Phạm Tộc Việt Nam Về Các HĐ Phạm Tộc địa phương Đồng thời là nơi để xem các thông báo chính thức của HĐ HPVN','','','publish','open','closed','','10724','','','2022-10-27 15:53:28','2022-10-27 08:53:28','',0,'http://www.hophamvietnam.org/?p=10724',2,'nav_menu_item','',0),(8925,1052,'2014-05-17 17:09:53','2014-05-17 10:09:53','<p style=\"text-align: center;\"><a title=\"http://www.hophamvietnam.org/1/\" href=\"http://www.hophamvietnam.org/1/\" target=\"_blank\" rel=\"noopener\">http://www.hophamvietnam.org/1/</a></p>\r\n<p style=\"text-align: center;\"><a href=\"http://www.hophamvietnam.org/1/\" target=\"_blank\" rel=\"noopener\"><img class=\"aligncenter  wp-image-8931\" alt=\"2005\" src=\"http://www.hophamvietnam.org/wp-content/uploads/2014/05/2005.png\" width=\"550\" /></a></p>\r\n<p style=\"text-align: center;\"><a title=\"http://www.hophamvietnam.org/1/\" href=\"http://www.hophamvietnam.org/1/\" target=\"_blank\" rel=\"noopener\">http://www.hophamvietnam.org/1/</a></p>','Tư Liệu Web 2005','','trash','open','closed','','phien-ban-2005__trashed','','','2021-12-28 23:42:15','2021-12-28 16:42:15','',0,'http://www.hophamvietnam.org/?page_id=8925',0,'page','',0),(8927,1052,'2014-05-17 17:10:07','2014-05-17 10:10:07','<p style=\"text-align: center;\"><a title=\"http://hophamvietnam.blogspot.com\" href=\"http://hophamvietnam.blogspot.com\" target=\"_blank\" rel=\"noopener\">http://hophamvietnam.blogspot.com</a></p>\r\n<p style=\"text-align: center;\"><a href=\"http://hophamvietnam.blogspot.com\" target=\"_blank\" rel=\"noopener\"><img class=\"aligncenter  wp-image-8937\" alt=\"2009\" src=\"http://www.hophamvietnam.org/wp-content/uploads/2014/05/2009.png\" width=\"550\" /></a></p>\r\n<p style=\"text-align: center;\"><a title=\"http://hophamvietnam.blogspot.com\" href=\"http://hophamvietnam.blogspot.com\" target=\"_blank\" rel=\"noopener\">http://hophamvietnam.blogspot.com</a></p>','Tư Liệu Web 2009','','trash','open','closed','','phien-ban-2009__trashed','','','2021-12-28 23:42:15','2021-12-28 16:42:15','',0,'http://www.hophamvietnam.org/?page_id=8927',0,'page','',0),(24634,1052,'2022-10-27 14:53